func serviceTimelineCategoryLabel(category string) string {
	switch strings.TrimSpace(category) {
	case "life":
		return "Life Event"
	case "service":
		return "Service Event"
	case "pension":
		return "Pension Trail"
	case "burial":
		return "Burial Context"
	case "death":
		return "Death Record"
	default:
		return "Source Context"
	}
}

func serviceTimelineCategoryClass(category string) string {
	switch strings.TrimSpace(category) {
	case "life":
		return "text-xs font-semibold uppercase tracking-[0.2em] text-[#8d7440]"
	case "service":
		return "text-xs font-semibold uppercase tracking-[0.2em] text-blue-600"
	case "pension":
		return "text-xs font-semibold uppercase tracking-[0.2em] text-[#6f2c26]"
	case "burial":
		return "text-xs font-semibold uppercase tracking-[0.2em] text-slate-500"
	case "death":
		return "text-xs font-semibold uppercase tracking-[0.2em] text-slate-700"
	default:
		return "text-xs font-semibold uppercase tracking-[0.2em] text-slate-500"
	}
}

